mapper.select:
/* com.educare.edu.comn.mapper.EtcGradeCodeMapper.selectByPage */
	select a.*
	from t_etc_grade_code a
	where 1=1

	order by a.grade_nm
	LIMIT #{firstRecordIndex} ,#{recordCountPerPage}

mapper.insert:
/* com.educare.edu.comn.mapper.EtcGradeCodeMapper.insertByPk */
	INSERT INTO t_etc_grade_code (
		grade_cd	,gong_gb_cd		,jikjong_cd		,jikgun_cd		,jikryul_cd		,jikryu_cd
		,grade_nm	,close_st
	) SELECT 
		#{gradeCd}	,#{gongGbCd}	,#{jikjongCd}	,#{jikgunCd}	,#{jikryulCd}	,#{jikryuCd}
		,#{gradeNm}	,#{closeSt}
    WHERE NOT EXISTS (
        SELECT 1 FROM t_etc_grade_code WHERE grade_cd = #{gradeCd}
    )

mapper.update:
/* com.educare.edu.comn.mapper.EtcGradeCodeMapper.updateByParam */
update t_etc_grade_code
set 


	jikjong_nm = #{jikjongNm}
	where jikjong_cd = #{jikjongCd}


	jikryul_nm = #{jikryulNm}
	where jikryul_cd = #{jikryulCd}


	jikryu_nm = #{jikryuNm}
	where jikryu_cd = #{jikryuCd}
